        float &tNear, uint32_t &index, Object **hitObject)  
{  
    *hitObject = nullptr;  
    for (uint32_t k = 0; k < objects.size(); ++k) {  
        float tNearK = kInfinity;  
        uint32_t indexK;  
        Vector2f uvK;  
        if (objects[k]->intersect(ray, tNearK, indexK) && tNearK < tNear) {  
